publish.value:
#ps
# Assuming this is already extracted from context
$noteText = $CTX.ticketNote[0]

# These are the sections we care about (excluding 'User activation')
$checkLabels = @(
    "Users made permanent",
    "Assignments made in PIM",
    "Assignments made outside of PIM"
)

$alertWorthy = $false

foreach ($label in $checkLabels) {
    if ($noteText -match "$label\s*\[(\d+)\]") {
        $count = [int]$matches[1]
        if ($count -gt 0) {
            $alertWorthy = $true
            break
        }
    }
}

return $alertWorthy

